  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { CopyToClipboard as CTC } from 'react-copy-to-clipboard';
  4	import Linkify from 'react-linkify';
  5	import { Tooltip } from '@patternfly/react-core';
  6	import { CopyIcon, ExternalLinkAltIcon } from '@patternfly/react-icons';
  7	import { useCustomTranslation } from '../useCustomTranslationHook';
  8	
  9	// Kubernetes "dns-friendly" names match
 10	// [a-z0-9]([-a-z0-9]*[a-z0-9])?  and are 63 or fewer characters
 11	// long. This pattern checks the pattern but not the length.
 12	//
 13	// Don't capture anything in legalNamePattern, since it's used
 14	// in expressions like
 15	//
 16	//    new RegExp("PREFIX" + legalNamePattern.source + "(SUFFIX)")
 17	//
 18	// And it's ok for users to make assumptions about capturing groups.
 19	
 20	export const ALL_NAMESPACES_KEY = '#ALL_NS#';
 21	
 22	export const legalNamePattern = /[a-z0-9](?:[-a-z0-9]*[a-z0-9])?/;
 23	
 24	// @ts-ignore (typescript error: Property 'SERVER_FLAGS' does not exist on type 'Window & typeof globalThis')
 25	const basePathPattern = new RegExp(`^/?${window.SERVER_FLAGS.basePath}`);
 26	
 27	export const namespacedPrefixes = [
 28	  '/api-resource',
 29	  '/k8s',
 30	  '/operatorhub',
 31	  '/operatormanagement',
 32	  '/operators',
 33	  '/details',
 34	  '/provisionedservices',
 35	  '/search',
 36	  '/status',
 37	];
 38	
 39	export const stripBasePath = (path: string): string =>
 40	  path.replace(basePathPattern, '/');
 41	
 42	export const getNamespace = (path: string): string => {
 43	  path = stripBasePath(path);
 44	  const split = path.split('/').filter((x) => x);
 45	
 46	  if (split[1] === 'all-namespaces') {
 47	    return ALL_NAMESPACES_KEY;
 48	  }
 49	
 50	  let ns: string;
 51	  if (
 52	    split[1] === 'cluster' &&
 53	    ['namespaces', 'projects'].includes(split[2]) &&
 54	    split[3]
 55	  ) {
 56	    ns = split[3];
 57	  } else if (split[1] === 'ns' && split[2]) {
 58	    ns = split[2];
 59	  } else {
 60	    return;
 61	  }
 62	
 63	  const match = ns.match(legalNamePattern);
 64	  return match && match.length > 0 && match[0];
 65	};
 66	
 67	export const getURLSearchParams = () => {
 68	  const all: any = {};
 69	  const params = new URLSearchParams(window.location.search);
 70	
 71	  for (const [k, v] of params.entries()) {
 72	    all[k] = v;
 73	  }
 74	
 75	  return all;
 76	};
 77	
 78	export const ExternalLink: React.FC<ExternalLinkProps> = ({
 79	  children,
 80	  href,
 81	  text,
 82	  additionalClassName = '',
 83	  dataTestID,
 84	  stopPropagation,
 85	}) => (
 86	  <a
 87	    className={classNames('co-external-link', additionalClassName)}
 88	    href={href}
 89	    target="_blank"
 90	    rel="noopener noreferrer"
 91	    data-test-id={dataTestID}
 92	    {...(stopPropagation ? { onClick: (e) => e.stopPropagation() } : {})}
 93	  >
 94	    {children || text}
 95	  </a>
 96	);
 97	
 98	// Opens link with copy-to-clipboard
 99	
100	export const ExternalLinkWithCopy: React.FC<ExternalLinkWithCopyProps> = ({
101	  link,
102	  text,
103	  additionalClassName,
104	  dataTestID,
105	}) => {
106	  const [copied, setCopied] = React.useState(false);
107	
108	  const { t } = useCustomTranslation();
109	  const tooltipText = copied
110	    ? t('Copied to clipboard')
111	    : t('Copy to clipboard');
112	  const tooltipContent = [
113	    <span className="co-nowrap" key="nowrap">
114	      {tooltipText}
115	    </span>,
116	  ];
117	
118	  return (
119	    <div className={classNames(additionalClassName)}>
120	      <a
121	        href={link}
122	        target="_blank"
123	        rel="noopener noreferrer"
124	        data-test-id={dataTestID}
125	      >
126	        {text ?? link}
127	      </a>
128	      <span className="co-icon-nowrap">
129	        &nbsp;
130	        <span className="co-external-link-with-copy__icon co-external-link-with-copy__externallinkicon">
131	          <ExternalLinkAltIcon />
132	        </span>
133	        <Tooltip
134	          content={tooltipContent}
135	          trigger="click mouseenter focus"
136	          exitDelay={1250}
137	        >
138	          <CTC text={link} onCopy={() => setCopied(true)}>
139	            <span
140	              onMouseEnter={() => setCopied(false)}
141	              className="co-external-link-with-copy__icon co-external-link-with-copy__copyicon"
142	            >
143	              <CopyIcon />
144	              <span className="sr-only">{t('Copy to clipboard')}</span>
145	            </span>
146	          </CTC>
147	        </Tooltip>
148	      </span>
149	    </div>
150	  );
151	};
152	
153	// Open links in a new window and set noopener/noreferrer.
154	export const LinkifyExternal: React.FC<{ children: React.ReactNode }> = ({
155	  children,
156	}) => (
157	  <Linkify properties={{ target: '_blank', rel: 'noopener noreferrer' }}>
158	    {children}
159	  </Linkify>
160	);
161	LinkifyExternal.displayName = 'LinkifyExternal';
162	
163	type ExternalLinkProps = {
164	  href: string;
165	  text?: React.ReactNode;
166	  additionalClassName?: string;
167	  dataTestID?: string;
168	  stopPropagation?: boolean;
169	};
170	
171	type ExternalLinkWithCopyProps = {
172	  link: string;
173	  text?: string;
174	  dataTestID?: string;
175	  additionalClassName?: string;
176	};

